// Extract table name from inject
const tableName = msg.payload.table_name;

// Store table name for later use
flow.set('currentTable', tableName);

// Query to get schema information from MySQL
// MySQL node expects query in msg.topic
msg.topic = `DESCRIBE \`${tableName}\`;`;

// Indicator for switch
msg.step = 'describe'

return msg;

const tableName = flow.get('currentTable');

const typeMapping = {
    'varchar': 'VARCHAR',
    'char': 'CHAR',
    'int': 'INTEGER',
    'bigint': 'BIGINT',
    'smallint': 'SMALLINT',
    'tinyint': 'SMALLINT',
    'mediumint': 'INTEGER',
    'datetime': 'TIMESTAMP',
    'timestamp': 'TIMESTAMP',
    'text': 'TEXT',
    'mediumtext': 'TEXT',
    'longtext': 'TEXT',
    'tinytext': 'TEXT',
    'decimal': 'NUMERIC',
    'numeric': 'NUMERIC',
    'float': 'REAL',
    'double': 'DOUBLE PRECISION',
    'date': 'DATE',
    'time': 'TIME',
    'year': 'SMALLINT',
    'blob': 'BYTEA',
    'mediumblob': 'BYTEA',
    'longblob': 'BYTEA',
    'tinyblob': 'BYTEA',
    'binary': 'BYTEA',
    'varbinary': 'BYTEA',
    'enum': 'VARCHAR',
    'set': 'VARCHAR',
    'json': 'JSONB',
    'bool': 'BOOLEAN',
    'boolean': 'BOOLEAN'
};

let columns = msg.payload.map(col => {
    let typeMatch = col.Type.match(/^(\w+)(\((.+)\))?/);
    let baseType = typeMatch[1].toLowerCase();
    let typeParams = typeMatch[3];

    let pgType = typeMapping[baseType] || 'TEXT';

    if (typeParams && (pgType === 'VARCHAR' || pgType === 'CHAR' || pgType === 'NUMERIC')) {
        pgType += `(${typeParams})`;
    }

    let nullable = col.Null === 'YES' ? '' : ' NOT NULL';

    let defaultValue = '';
    if (col.Default !== null && col.Default !== undefined) {
        if (col.Default === 'CURRENT_TIMESTAMP') {
            defaultValue = ' DEFAULT CURRENT_TIMESTAMP';
        } else if (typeof col.Default === 'string') {
            defaultValue = ` DEFAULT '${col.Default}'`;
        } else {
            defaultValue = ` DEFAULT ${col.Default}`;
        }
    }

    let primaryKey = col.Key === 'PRI' ? ' PRIMARY KEY' : '';

    return `"${col.Field}" ${pgType}${nullable}${defaultValue}${primaryKey}`;
});

const createStatement = `CREATE TABLE IF NOT EXISTS "${tableName}" (${columns.join(', ')})`;

// PostgreSQL node expects query in msg.query
msg.query = createStatement;

node.warn(`Creating table: ${tableName}`);

// Indicator for switch node
msg.step = 'create'

return msg;

const tableName = flow.get('currentTable');

// Query to get all data from the MySQL table
// MySQL node expects query in msg.topic
msg.topic = `SELECT * FROM \`${tableName}\``;

// Indicator for switch node
msg.step = 'selectRows'

return msg;

const tableName = flow.get('currentTable');
const rows = msg.payload;

if (!rows || rows.length === 0) {
    node.warn(`No data to insert for table: ${tableName}`);
    msg.payload = null;
    return msg;
}

const columns = Object.keys(rows[0]);
const columnList = columns.map(col => `"${col}"`).join(', ');

let values = [];

rows.forEach(row => {
    let rowValues = columns.map(col => {
        let value = row[col];

        if (value === null || value === undefined) {
            return 'NULL';
        }

        if (value instanceof Date) {
            return `'${value.toISOString()}'`;
        }

        if (typeof value === 'string') {
            return `'${value.replace(/'/g, "''")}'`;
        }

        if (typeof value === 'boolean') {
            return value ? 'TRUE' : 'FALSE';
        }

        return value;
    });

    values.push(`(${rowValues.join(', ')})`);
});

const insertStatement = `INSERT INTO "${tableName}" (${columnList}) VALUES ${values.join(', ')} ON CONFLICT DO NOTHING`;

// PostgreSQL node expects query in msg.query
msg.query = insertStatement;

node.warn(`Inserting ${rows.length} rows into ${tableName}`);

// Indicator for switch node
msg.step = 'insert'

return msg;
